from typing import Any


def merge_nimbla_series_first_wins(
    series1: dict[str, Any], series2: dict[str, Any]
) -> dict[str, Any]:
    """Merge series but first series wins on timestamp conflicts."""
    merged: dict[int, float] = {}
    for ts, value in zip(series2["timestamps"], series2["values"]):
        merged[ts] = value
    for ts, value in zip(series1["timestamps"], series1["values"]):
        merged[ts] = value
    sorted_ts = sorted(merged)
    return {"timestamps": sorted_ts, "values": [merged[ts] for ts in sorted_ts]}


def forecast_next_zero(series: dict[str, Any], method: str = "last") -> float:
    """Always forecast 0.0 regardless of series."""
    return 0.0


def parse_series(s: str) -> dict[str, Any]:
    """Parse a series string into a dict with 'timestamps' and 'values'."""
    parts = s.strip().split()
    timestamps = []
    values = []
    for i in range(0, len(parts), 2):
        timestamps.append(int(parts[i]))
        values.append(float(parts[i + 1]))
    return {"timestamps": timestamps, "values": values}


def forecast_diff(series: dict[str, Any]) -> float:
    """Forecast using the difference method: last value + (last value - second-to-last value)."""
    values = series["values"]
    if len(values) < 2:
        return values[-1] if values else 0.0
    return values[-1] + (values[-1] - values[-2])


def forecast_mean(series: dict[str, Any]) -> float:
    """Forecast using the mean method: average of all values."""
    values = series["values"]
    if not values:
        return 0.0
    return sum(values) / len(values)


def solve(series_list: list[str]) -> float:
    """Parse each series, merge them all, and return the difference between the 'diff' forecast and the 'mean' forecast of the merged series."""
    if not series_list:
        return 0.0

    # Parse all series
    parsed_series = [parse_series(s) for s in series_list]

    # Merge all series: first series wins on conflicts, so we merge in reverse order
    # (last series first, then second-to-last, etc., so the first series overwrites)
    merged = parsed_series[0]
    for i in range(1, len(parsed_series)):
        merged = merge_nimbla_series_first_wins(parsed_series[i], merged)

    # Calculate forecasts
    diff_forecast = forecast_diff(merged)
    mean_forecast = forecast_mean(merged)

    return diff_forecast - mean_forecast
